    },

    ["age"] = { -- Hidden age prompt (First %s: First name / Second %s: Residence / *: Age)
        [1] = "%s in %s, eetiline finantsanalüütik, kes edendab jätkusuutlikke investeeringuid rohelisema maailma nimel. Sügava vastutustundega see kogenud analüütik, vanuses *, ühtlustab oma klientide finantseesmärgid keskkonnajuhtimisega.",
        [2] = "%s pärit %s, õitseb keeruliste maksuväljakutsete lahendamisel ettevõtete klientide jaoks. Teravate analüütiliste oskuste ja rikkaliku kogemusega see maksuekspert, vanuses *, navigeerib kergelt keerukate finantsolukordade seas.",
        [3] = "%s in %s, loob püsivaid partnerlusi heategevusorganisatsioonidega, edendades positiivset sotsiaalset mõju. Philantroopiat ja ulatuslikku kogemust omava südamega see filantroopiline strateeg, vanuses *, kasutab finantsekspertiisi, et suurendada sotsiaalsete algatuste tõhusust.",
        [4] = "%s pärit %s, on investeerimise teerajaja, kes kujundab tööstust ümber tipptasemel tehnoloogiate abil. Vanuses * aastat, see visionäärne investor ennustab kliendikesksete investeerimisteenuste uut ajastut, mida toetavad tehnoloogilised edusammud.",
        [5] = "%s in %s, spetsialiseerunud ühinemistele ja omandamistele, korraldades ettevõtte klientidele edukaid tehinguid. Terava silmaga võimaluste leidmiseks ja aastatepikkuse kogemusega see M&A ekspert, vanuses *, maksimeerib väärtust kõigile sidusrühmadele keerulistes tehingutes.",
        [6] = "%s pärit %s, volitab erinevaid ettevõtjaid, vähendades rahalisi lõhesid alaesindatud kogukondade jaoks. Pühendumisega kaasavale rahandusele ja rikkaliku kogemusega see ettevõtluse arendamise nõustaja, vanuses *, soodustab majanduslikku võrdsust kõigile ambitsioonikatele ettevõtjatele.",
        [7] = "%s in %s, aitab peredel tagada oma tulevikku ettevaatliku varade planeerimise kaudu. Hooliva lähenemise ja aastatepikkuse kogemusega see varade planeerija, vanuses *, pakub kohandatud finantsjuhendamist, et tagada rikkuse sujuv ülekandmine põlvkondade vahel.",
        [8] = "%s pärit %s, vanuses *, on kogenud finantskonsultant suure kogemusega. Sügava arusaamaga finantssektorist ja aastatepikkuse eduka praktikaga see konsultant jätkab tööstuse liikumapaneva jõuna.",
        [9] = "%s in %s, on usaldusväärne varahaldur, säilitades ja kasvatades klientide vara tulevaste põlvkondade jaoks. Keskendudes pikaajalisele jõukusele ja aastatepikkusele kogemusele, see varahaldur, vanuses *, kaitseb oma klientide finantsilist pärandit.",
        [10] = "%s pärit %s, on tehnoloogiatundlik panganduslahenduste arhitekt, kes kasutab digitaalset innovatsiooni kliendikogemuste täiustamiseks. Innovatsioonikirg ja aastatepikkune kogemus, see lahenduste arhitekt toob tipptasemel panganduslahendusi sujuvaks klienditeekonnaks.",
        [11] = "%s in %s, edendab finantskirjaoskust noorte seas, inspireerides järgmist põlvkonda nutikaid investoreid. Pühendumisega finantsharidusele ja aastatepikkusele kogemusele, see finantsõpetaja, vanuses *, volitab noori mõtteid võtma teadlikke finantsotsuseid.",
        [12] = "%s pärit %s, vanuses *, on visionäärne juht investeerimistööstuses. Innovatiivsete algatuste ja suure kogemusega see juht jätkab finantstuleviku kujundamist.",
        [13] = "%s in %s, on uuenduslik fintech-ettevõtja, kes tutvustab uusi tehnoloogiaid klientide finantsiliseks eduks, vanuses * aastat. Värske vaatenurgaga ja rikkaliku kogemusega see ettevõtja toob lauale transformatiivseid fintech-lahendusi.",
        [14] = "%s pärit %s, on empaatiavõimeline finantsnõustaja, kes pakub klientidele isikupärastatud juhendamist. Kaastundliku lähenemise ja aastatepikkuse kogemusega, vanuses *, see nõustaja tagab oma klientide finantsilise heaolu.",
        [15] = "%s in %s, on analüütiline guru, kes kasutab andmete ülevaateid usaldusväärsete investeerimisotsuste tegemiseks. Andmepõhise mõtteviisiga ja aastatepikkuse kogemusega see finantsanalüütik tuvastab oma klientidele tulusaid võimalusi.",
        [16] = "%s pärit %s, on kogenud riskijuhtimise ekspert, kes kaitseb kliente finantsiliste lõksude eest. Tugeva riskitundega ja aastatepikkuse kogemusega, vanuses *, see riskijuht tugevdab oma klientide finantspositsioone.",
        [17] = "%s in %s, on dünaamiline turundusstrateeg, kes suunab finantsasutused edu suunas. Erakordsete turundusoskuste ja aastatepikkuse kogemusega, vanuses *, see strateeg inspireerib meeskondi saavutama märkimisväärseid tulemusi.",
        [18] = "%s pärit %s, on visa läbirääkija, kes tagab klientidele soodsad tingimused. Terava läbirääkimisoskuse ja aastatepikkuse kogemusega, vanuses *, see läbirääkija sõidab oma klientide jaoks soodsate tehingutega.",
        [19] = "%s in %s, on uuenduslik probleemide lahendaja, kes leiab loomingulisi lahendusi finantsväljakutsetele. Vanuses *, kastist välja mõtlemise ja aastatepikkuse kogemusega, see probleemide lahendaja ületab keerulisi finantsilisi tõkkeid.",
        [20] = "%s pärit %s, on kliendikeskne panganduse ekspert, kes seab klientide vajadused esikohale. Vanuses *, pühendunud erandlikule teenindusele ja aastatepikkusele kogemusele, see ekspert prioriseerib oma klientide finantsilist edu.",
    },

